// src/pages/HomeScreen.js
import React, { useMemo, useState } from "react";
import {
  SafeAreaView,
  View,
  Text,
  StyleSheet,
  Image,
  TextInput,
  TouchableOpacity,
  Platform,
  useWindowDimensions,
} from "react-native";
import { LinearGradient } from "expo-linear-gradient";

const nalicoreLogo = require("../../assets/nalicore_logo.png");

export default function HomeScreen() {
  const { width, height } = useWindowDimensions();

  const isSmall = width < 380;
  const isMobile = width < 768;
  const isDesktop = width >= 1024;

  // In mockup #2 the content is centered and not too wide
  const containerMaxWidth = isDesktop ? 560 : 560;

  const [query, setQuery] = useState("Total borne 10 entre\nenfant noir chez le boss");

  const resolved = useMemo(
    () => ({
      quartier: "Odza",
      secteur: "Borne 10",
      sousSecteur: "Total borne 10",
      entree: "Enfant Noir",
      lieu: "Chez le Boss",
      banoc: "Q5TCL",
      latitude: 3.7862,
      longitude: 111.53045,
    }),
    []
  );

  const onResolve = () => console.log("Resolve:", query);
  const onNavigate = () =>
    console.log("Navigate:", resolved.latitude, resolved.longitude);

  return (
    <SafeAreaView style={styles.safe}>
      {/* Soft gradient background like mockup */}
      <LinearGradient
        colors={["#E9ECF6", "#E6E2F3", "#ECEAF8", "#E9ECF6"]}
        start={{ x: 0.1, y: 0.0 }}
        end={{ x: 0.9, y: 1.0 }}
        style={styles.bg}
      >
        {/* Big rounded "glass" panel */}
        <View style={[styles.shell, { maxWidth: containerMaxWidth }]}>
          {/* Header (no separate pill; it sits in the glass) */}
          <View style={styles.headerRow}>
            <Image
              source={nalicoreLogo}
              style={[styles.logo, { width: isSmall ? 190 : 230 }]}
              resizeMode="contain"
            />
            <Text
              style={[
                styles.tagline,
                { fontSize: isSmall ? 14 : 16, lineHeight: isSmall ? 18 : 22 },
              ]}
              numberOfLines={2}
            >
              Natural Address{"\n"}Location Infrastructure
            </Text>
          </View>

          {/* Search bar + resolve button (rounded, soft, like mockup) */}
          <View style={styles.searchWrap}>
            <View style={styles.searchLeft}>
              <SearchIcon />
              <TextInput
                value={query}
                onChangeText={setQuery}
                style={[
                  styles.searchInput,
                  {
                    fontSize: isSmall ? 15 : 16,
                    lineHeight: isSmall ? 20 : 22,
                  },
                ]}
                placeholder="Type an address…"
                placeholderTextColor="rgba(15,23,42,0.45)"
                multiline
                numberOfLines={2}
                scrollEnabled={false}
                textAlignVertical="center"
                underlineColorAndroid="transparent"
              />
            </View>

            <View style={styles.searchDivider} />

            <TouchableOpacity
              activeOpacity={0.92}
              style={[styles.resolveBtn, { width: isSmall ? 130 : 150 }]}
              onPress={onResolve}
            >
              <LinearGradient
                colors={["#2F5DBB", "#2A56B4", "#254EAA"]}
                start={{ x: 0, y: 0 }}
                end={{ x: 1, y: 1 }}
                style={styles.resolveBtnBg}
              >
                <Text style={[styles.resolveText, { fontSize: isSmall ? 16 : 18 }]}>
                  Resolve
                </Text>
              </LinearGradient>
            </TouchableOpacity>
          </View>

          {/* Resolved card (inner header strip like mockup) */}
          <View style={styles.cardOuter}>
            <View style={styles.cardHeaderStrip}>
              <Text style={[styles.cardTitle, { fontSize: isSmall ? 20 : 22 }]}>
                Resolved Address
              </Text>
            </View>

            <View style={styles.cardBody}>
              <Row label="Quartier:" value={resolved.quartier} isSmall={isSmall} />
              <Row label="Secteur:" value={resolved.secteur} isSmall={isSmall} />
              <Row label="Sous-secteur:" value={resolved.sousSecteur} isSmall={isSmall} />
              <Row label="Entrée:" value={resolved.entree} isSmall={isSmall} />
              <Row label="Lieu:" value={resolved.lieu} isSmall={isSmall} />

              <View style={styles.row}>
                <Text style={[styles.label, { fontSize: isSmall ? 14 : 15 }]}>
                  BANOC:
                </Text>
                <View style={styles.banocPill}>
                  <Text style={styles.banocText}>{resolved.banoc}</Text>
                </View>
              </View>

              {/* Mockup has GPS + separate Latitude/Longitude. Keep yours clean: */}
              <Row
                label="GPS:"
                value={`${Number(resolved.latitude).toFixed(5)}, ${Number(resolved.longitude).toFixed(5)}`}
                isSmall={isSmall}
              />

              <Row
                label="Latitude:"
                value={Number(resolved.latitude).toFixed(5)}
                isSmall={isSmall}
              />
              <Row
                label="Longitude:"
                value={Number(resolved.longitude).toFixed(5)}
                isSmall={isSmall}
              />

              <TouchableOpacity activeOpacity={0.92} style={styles.navBtn} onPress={onNavigate}>
                <View style={styles.navIconWrap}>
                  <PinIconFilled />
                </View>
                <Text style={[styles.navText, { fontSize: isSmall ? 17 : 18 }]}>
                  Navigate to Location
                </Text>
              </TouchableOpacity>
            </View>
          </View>
        </View>

        {/* keep screen non-scroll but visually balanced on tall screens */}
        <View style={{ height: Math.max(18, Math.floor(height * 0.04)) }} />
      </LinearGradient>
    </SafeAreaView>
  );
}

